const ctx  = $input.first().json;
const best = ctx.best_pair || "EURUSD";
const base  = best.slice(0, 3);
const quote = best.slice(3, 6);

// Filtrar noticias por moneda del par; si no hay, usar todas
const allNews = (ctx.news || []);
const byPair  = allNews.filter(n => {
  const c = (n.currency || '').toUpperCase();
  return c === base || c === quote || c === '';
}).slice(0, 6);
const relevant = byPair.length > 0 ? byPair : allNews.slice(0, 6);

const newsLines = relevant.length > 0
  ? relevant.map(n => `- [${(n.impact || 'low').toUpperCase()}] ${n.headline}`).join('\n')
  : '- No news available';

// Posiciones: array plano, no objeto {open:[]}
const positions = Array.isArray(ctx.positions) ? ctx.positions : [];
const open   = positions.filter(p => p.symbol === best);
const longV  = open.filter(p => p.type === 'BUY' ).reduce((s, p) => s + (p.volume || 0), 0);
const shortV = open.filter(p => p.type === 'SELL').reduce((s, p) => s + (p.volume || 0), 0);
const total  = longV + shortV;
const posInfo = total > 0
  ? `Long ${longV.toFixed(2)} lots, Short ${shortV.toFixed(2)} lots (${((longV - shortV) / total * 100).toFixed(1)}% long bias)`
  : 'No open positions';

const prompt = `You are a market sentiment analyst for forex trading.
Analyze market sentiment for ${best} (${base} vs ${quote}) based on recent news.

Symbol: ${best}
Recent news:
${newsLines}

Current positioning: ${posInfo}

Rules:
- Positive/hawkish news for ${base} → buy. Negative/dovish → sell.
- Risk-off (geopolitical fear, recession) → CHF/JPY/USD bid depending on pair.
- Extreme positioning (>70% one side) suggests contrarian signal.
- If news clearly favor one direction, commit to it with confidence 0.7-0.9.
- Only return "neutral" if signals are genuinely contradictory.

Respond with ONLY this JSON (no markdown, no explanation):
{"signal":"buy|sell|neutral","confidence":0.0-1.0,"reason":"one sentence"}`;

return [{ json: { ...ctx, prompt } }];

